import requests
import time

def call_api_with_retry(url, max_retries=3, delay=1):
    """
    带重试机制的 API 调用函数。

    参数:
        url (str): API 的 URL。
        max_retries (int): 最大重试次数，默认为 3。
        delay (int): 重试之间的延迟秒数，默认为 1。

    返回:
        dict: API 响应数据，如果成功。
        None: 如果所有重试都失败。
    """
    for attempt in range(max_retries):
        try:
            response = requests.get(url, timeout=5)
            response.raise_for_status()  # 检查 HTTP 错误
            return response.json()
        except requests.exceptions.RequestException as e:
            print(f"尝试 {attempt + 1} 失败: {e}")
            if attempt < max_retries - 1:
                time.sleep(delay)
            else:
                print("所有重试均失败")
                return None

# 示例使用
if __name__ == "__main__":
    result = call_api_with_retry("https://api.example.com/data")
    if result:
        print("API 调用成功:", result)
    else:
        print("API 调用失败")

import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

public class ScheduledTaskManager {
    private ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
    private int taskCount = 0;

    public void startTask() {
        scheduler.scheduleAtFixedRate(() -> {
            taskCount++;
            System.out.println("Task executed, count: " + taskCount);
            // Simulate some work
            try {
                Thread.sleep(1000);
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }, 0, 2, TimeUnit.SECONDS);
    }

    public void stopTask() {
        scheduler.shutdown();
        try {
            if (!scheduler.awaitTermination(5, TimeUnit.SECONDS)) {
                scheduler.shutdownNow();
            }
        } catch (InterruptedException e) {
            scheduler.shutdownNow();
        }
    }

    public static void main(String[] args) {
        ScheduledTaskManager manager = new ScheduledTaskManager();
        manager.startTask();
        // Let it run for a while
        try {
            Thread.sleep(10000);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        manager.stopTask();
    }
}

package main

import (
    "fmt"
    "net/http"
    "sync"
    "time"
)

type Message struct {
    ID        int
    SenderID  int
    ReceiverID int
    Content   string
    Timestamp time.Time
}

type MessageService struct {
    messages []Message
    mu       sync.Mutex
}

func (ms *MessageService) SendMessage(senderID, receiverID int, content string) error {
    if len(content) > 1000 {
        return fmt.Errorf("content too long")
    }
    msg := Message{
        ID:        len(ms.messages) + 1,
        SenderID:  senderID,
        ReceiverID: receiverID,
        Content:   content,
        Timestamp: time.Now(),
    }
    ms.mu.Lock()
    ms.messages = append(ms.messages, msg)
    ms.mu.Unlock()
    return nil
}

func (ms *MessageService) GetMessages(userID int) []Message {
    var userMessages []Message
    for _, msg := range ms.messages {
        if msg.ReceiverID == userID || msg.SenderID == userID {
            userMessages = append(userMessages, msg)
        }
    }
    return userMessages
}

func handleSendMessage(w http.ResponseWriter, r *http.Request) {
    if r.Method != "POST" {
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
        return
    }
    senderID := r.FormValue("sender_id")
    receiverID := r.FormValue("receiver_id")
    content := r.FormValue("content")
    if senderID == "" || receiverID == "" || content == "" {
        http.Error(w, "Missing parameters", http.StatusBadRequest)
        return
    }
    var sID, rID int
    fmt.Sscanf(senderID, "%d", &sID)
    fmt.Sscanf(receiverID, "%d", &rID)
    ms := &MessageService{}
    err := ms.SendMessage(sID, rID, content)
    if err != nil {
        http.Error(w, err.Error(), http.StatusInternalServerError)
        return
    }
    w.WriteHeader(http.StatusOK)
    fmt.Fprintf(w, "Message sent successfully")
}

func main() {
    http.HandleFunc("/send", handleSendMessage)
    http.ListenAndServe(":8080", nil)
}

