const cache = new Map();
const maxCacheSize = 1000;
const defaultTTL = 30000; // 30 seconds

async function fetchDataFromSource(key) {
    // Simulate fetching data from an external source
    await new Promise(resolve => setTimeout(resolve, 100));
    return { data: `Data for ${key}`, timestamp: Date.now() };
}

async function getCachedData(key) {
    const now = Date.now();
    if (cache.has(key)) {
        const entry = cache.get(key);
        if (now - entry.timestamp < defaultTTL) {
            return entry.data;
        } else {
            cache.delete(key);
        }
    }

    try {
        const data = await fetchDataFromSource(key);
        cache.set(key, { data: data.data, timestamp: data.timestamp });

        // Evict oldest entries if cache exceeds max size
        if (cache.size > maxCacheSize) {
            const oldestKey = Array.from(cache.keys())[0];
            cache.delete(oldestKey);
        }

        return data.data;
    } catch (error) {
        console.error(`Failed to fetch data for key: ${key}`, error);
        return null;
    }
}

// Example usage
async function main() {
    const result1 = await getCachedData('user:123');
    console.log(result1);

    // Simulate concurrent access
    setTimeout(() => getCachedData('user:123'), 10);
    setTimeout(() => getCachedData('user:456'), 20);
}

