CREATE TABLE user_cache (
    user_id INT PRIMARY KEY,
    username VARCHAR(50),
    last_login TIMESTAMP,
    cache_timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE OR REPLACE FUNCTION get_user_data(user_id_param INT)
RETURNS TABLE(username VARCHAR, last_login TIMESTAMP) AS $$
BEGIN
    -- 检查缓存中是否有数据
    SELECT username, last_login
    INTO username, last_login
    FROM user_cache
    WHERE user_id = user_id_param AND cache_timestamp > NOW() - INTERVAL '1 hour';

    -- 如果缓存未命中，从主表获取并更新缓存
    IF NOT FOUND THEN
        SELECT username, last_login
        INTO username, last_login
        FROM users
        WHERE user_id = user_id_param;

        INSERT INTO user_cache (user_id, username, last_login, cache_timestamp)
        VALUES (user_id_param, username, last_login, NOW())
        ON CONFLICT (user_id) DO UPDATE SET
            username = EXCLUDED.username,
            last_login = EXCLUDED.last_login,
            cache_timestamp = NOW();
    END IF;

    RETURN NEXT;
END;
$$ LANGUAGE plpgsql;

