CREATE OR REPLACE PROCEDURE process_memory_mapped_file(
    file_path VARCHAR(255),
    output_table VARCHAR(255)
)
AS $$
DECLARE
    file_content BYTEA;
    file_size BIGINT;
    buffer BYTEA;
    offset BIGINT := 0;
    chunk_size INTEGER := 4096;
    data_row RECORD;
    insert_query TEXT;
BEGIN
    -- Read file content with error handling
    BEGIN
        file_content := pg_read_binary_file(file_path);
    EXCEPTION
        WHEN OTHERS THEN
            RAISE EXCEPTION 'Error reading file %: %', file_path, SQLERRM;
    END;

    IF file_content IS NULL THEN
        RAISE EXCEPTION 'File not found or empty: %', file_path;
    END IF;

    file_size := octet_length(file_content);

    -- Prepare insert query once to avoid repeated parsing
    insert_query := format('INSERT INTO %I (id, value) VALUES ($1, $2)', output_table);

    -- Process file in chunks with bulk-like optimization
    WHILE offset < file_size LOOP
        buffer := substring(file_content FROM offset + 1 FOR chunk_size);

        -- Parse buffer into rows (simplified example)
        data_row.id := (buffer::TEXT)[1:10];
        data_row.value := (buffer::TEXT)[11:20];

        -- Execute prepared insert
        EXECUTE insert_query USING data_row.id, data_row.value;

        offset := offset + chunk_size;
    END LOOP;

    -- Explicitly clear large variable to free memory
    file_content := NULL;

    RAISE NOTICE 'File processed successfully: %', file_path;
END;
$$ LANGUAGE plpgsql;

