CREATE OR REPLACE PROCEDURE process_memory_mapped_files()
LANGUAGE plpgsql
AS $$
DECLARE
    file_path TEXT := '/var/data/large_file.dat';
    file_handle INTEGER;
    buffer BYTEA;
    chunk_size INTEGER := 1048576; -- 1 MB
    total_read INTEGER := 0;
    file_size INTEGER;
BEGIN
    -- Open file for reading
    file_handle := pg_ls_dir(file_path);
    IF file_handle IS NULL THEN
        RAISE EXCEPTION 'File not found: %', file_path;
    END IF;

    -- Get file size
    SELECT pg_stat_file(file_path).size INTO file_size;

    -- Process file in chunks using memory mapping
    WHILE total_read < file_size LOOP
        buffer := pg_read_binary_file(file_path, total_read, chunk_size);
        IF buffer IS NULL THEN
            EXIT;
        END IF;

        -- Simulate processing: convert to uppercase and write to log
        PERFORM log_processed_chunk(UPPER(buffer::TEXT));

        total_read := total_read + chunk_size;
        IF total_read > file_size THEN
            total_read := file_size;
        END IF;
    END LOOP;

    -- Close file handle
    PERFORM pg_ls_dir_close(file_handle);

    RAISE NOTICE 'File processing completed successfully.';
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE 'Error occurred: %', SQLERRM;
END;
$$;

import pika
import json
import time

class MessageQueueProducer:
    def __init__(self, host='localhost'):
        self.connection = pika.BlockingConnection(pika.ConnectionParameters(host=host))
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue='task_queue', durable=True)

    def send_message(self, message):
        try:
            body = json.dumps(message)
            self.channel.basic_publish(
                exchange='',
                routing_key='task_queue',
                body=body,
                properties=pika.BasicProperties(
                    delivery_mode=2,  # make message persistent
                ))
            print(f"Sent: {message}")
        except Exception as e:
            print(f"Error sending message: {e}")

    def close(self):
        if self.connection:
            self.connection.close()

# 示例使用
producer = MessageQueueProducer()
for i in range(10):
    producer.send_message({'task_id': i, 'data': f'task_{i}'})
    time.sleep(0.5)
producer.close()

import java.io.FileOutputStream;
import java.io.IOException;
import com.itextpdf.text.Document;
import com.itextpdf.text.DocumentException;
import com.itextpdf.text.Paragraph;
import com.itextpdf.text.pdf.PdfWriter;

public class PdfGenerator {
    private String outputPath;
    private int maxRetries = 3;
    private static final Object lock = new Object();

    public PdfGenerator(String outputPath) {
        this.outputPath = outputPath;
    }

    public void generatePdf(String content) {
        synchronized (lock) {
            Document document = new Document();
            try {
                PdfWriter.getInstance(document, new FileOutputStream(outputPath));
                document.open();
                document.add(new Paragraph(content));
                document.close();
            } catch (DocumentException | IOException e) {
                System.err.println("Error generating PDF: " + e.getMessage());
                for (int i = 0; i < maxRetries; i++) {
                    try {
                        Thread.sleep(1000);
                        PdfWriter.getInstance(document, new FileOutputStream(outputPath));
                        document.open();
                        document.add(new Paragraph(content));
                        document.close();
                        break;
                    } catch (Exception ex) {
                        if (i == maxRetries - 1) {
                            System.err.println("Failed after retries: " + ex.getMessage());
                        }
                    }
                }
            } finally {
                if (document != null && document.isOpen()) {
                    document.close();
                }
            }
        }
    }

    public static void main(String[] args) {
        PdfGenerator generator = new PdfGenerator("output.pdf");
        generator.generatePdf("Sample PDF content");
    }
}

CREATE FUNCTION ConvertColorFormat(color VARCHAR(20)) RETURNS VARCHAR(20)
BEGIN
    DECLARE result VARCHAR(20);
    IF color LIKE '#%' THEN
        SET result = REPLACE(color, '#', '0x');
    ELSEIF color LIKE 'rgb(%' THEN
        SET result = REPLACE(color, 'rgb(', '');
        SET result = REPLACE(result, ')', '');
        SET result = CONCAT('0x', REPLACE(result, ',', ''));
    ELSEIF color LIKE 'hsl(%' THEN
        SET result = REPLACE(color, 'hsl(', '');
        SET result = REPLACE(result, ')', '');
        SET result = CONCAT('0x', REPLACE(result, ',', ''));
    ELSE
        SET result = 'Invalid format';
    END IF;
    RETURN result;
END;

